@app.route('/api/v1/tables', methods=['GET'])
def list_tables():
    """List available tables."""
    try:
        conn = get_db_connection()
        try:
            with conn.cursor() as cur:
                cur.execute("""
                    SELECT table_schema, table_name 
                    FROM information_schema.tables 
                    WHERE table_schema NOT IN ('pg_catalog', 'information_schema')
                    AND table_type = 'BASE TABLE'
                    ORDER BY table_schema, table_name
                """)
                tables = []
                for row in cur.fetchall():
                    full_name = f"{row[0]}.{row[1]}" if row[0] != 'public' else row[1]
                    # If whitelist is configured, only show allowed tables
                    if ALLOWED_TABLES and full_name not in ALLOWED_TABLES and row[1] not in ALLOWED_TABLES:
                        continue
                    tables.append({
                        "schema": row[0],
                        "table": row[1],
                        "full_name": full_name
                    })

            return jsonify({"success": True, "tables": tables}), 200
        finally:
            conn.close()
    except psycopg2.Error as e:
        return jsonify({"error": f"Database error: {str(e)}"}), 500


@app.route('/api/v1/tables/<table_name>/columns', methods=['GET'])
def list_columns(table_name):
    """List columns for a specific table."""
    try:
        valid, error = validate_table(table_name)
        if not valid:
            return jsonify({"error": error}), 400

        schema = 'public'
        table = table_name
        if '.' in table_name:
            schema, table = table_name.split('.', 1)

        conn = get_db_connection()
        try:
            with conn.cursor() as cur:
                cur.execute("""
                    SELECT column_name, data_type, is_nullable, column_default,
                           character_maximum_length, numeric_precision
                    FROM information_schema.columns 
                    WHERE table_schema = %s AND table_name = %s
                    ORDER BY ordinal_position
                """, (schema, table))

                columns = []
                for row in cur.fetchall():
                    columns.append({
                        "name": row[0],
                        "data_type": row[1],
                        "nullable": row[2] == 'YES',
                        "default": row[3],
                        "max_length": row[4],
                        "numeric_precision": row[5]
                    })

                if not columns:
                    return jsonify({"error": f"Table '{table_name}' not found"}), 404

            return jsonify({"success": True, "table": table_name, "columns": columns}), 200
        finally:
            conn.close()
    except psycopg2.Error as e:
        return jsonify({"error": f"Database error: {str(e)}"}), 500


